#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#define MAXN 1000
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int is_convex(int *sticks, int k) {
    int i, j;
    double area = 0;
    for (i = 0; i < k; i++) {
        j = (i + 1) % k;
        area += sticks[i] * sticks[j];
    }
    return area > 0;
}
int main() {
    int T, n, k, i, j;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &k);
        int sticks[MAXN];
        for (i = 0; i < n; i++) {
            scanf("%d", &sticks[i]);
        }
        qsort(sticks, n, sizeof(int), compare);
        for (i = 0; i <= n - 2 * k; i++) {
            for (j = i + k; j <= n - k; j++) {
                int first_k[MAXN], second_k[MAXN];
                for (int l = 0; l < k; l++) {
                    first_k[l] = sticks[i + l];
                    second_k[l] = sticks[j + l];
                }
                if (is_convex(first_k, k) && is_convex(second_k, k)) {
                    printf("Yes\n");
                    for (int l = 0; l < k; l++) {
                        printf("%d ", i + l + 1);
                    }
                    for (int l = 0; l < k; l++) {
                        printf("%d ", j + l + 1);
                    }
                    printf("\n");
                    break;
                }
            }
            if (i <= n - 2 * k && j <= n - k) break;
        }
        if (i > n - 2 * k || j > n - k) printf("No\n");
    }
    return 0;
}

