import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int n = scanner.nextInt();
            int k = scanner.nextInt();
            int[] sticks = new int[n];
            for (int i = 0; i < n; i++) {
                sticks[i] = scanner.nextInt();
            }
            Arrays.sort(sticks);
            boolean found = false;
            for (int i = 0; i <= n - 2 * k; i++) {
                for (int j = i + k; j <= n - k; j++) {
                    int[] first_k = new int[k];
                    int[] second_k = new int[k];
                    for (int l = 0; l < k; l++) {
                        first_k[l] = sticks[i + l];
                        second_k[l] = sticks[j + l];
                    }
                    if (isConvex(first_k, k) && isConvex(second_k, k)) {
                        System.out.println("Yes");
                        for (int l = 0; l < k; l++) {
                            System.out.print((i + l + 1) + " ");
                        }
                        for (int l = 0; l < k; l++) {
                            System.out.print((j + l + 1) + " ");
                        }
                        System.out.println();
                        found = true;
                        break;
                    }
                }
                if (found) break;
            }
            if (!found) System.out.println("No");
        }
    }
    public static boolean isConvex(int[] sticks, int k) {
        int i, j;
        double area = 0;
        for (i = 0; i < k; i++) {
            j = (i + 1) % k;
            area += sticks[i] * sticks[j];
        }
        return area > 0;
    }
}

